const Logger={_isDev: typeof process!=='undefined'&&process.env?.NODE_ENV==='development',error(message,data){console.error(`[Error] ${message}`,data||'');},warn(message,data){console.warn(`[Warn] ${message}`,data||'');},info(message,data){console.info(`[Info] ${message}`,data||'');},debug(message,data){},table(data,columns){if(this._isDev){console.table(data,columns);}},group(label){if(this._isDev&&console.group){console.group(`[Group] ${label}`);}},groupEnd(){if(this._isDev&&console.groupEnd){console.groupEnd();}},handleError(error,options={}){const{showToast=true,logToConsole=true,userMessage='Có lỗi xảy ra'}=options;if(logToConsole){this.error(error.message,error);}if(showToast&&typeof window!=='undefined'){if(window.Toast?.error){window.Toast.error(userMessage);}else if(window.Alert?.error){window.Alert.error('Lỗi',userMessage);}}}};export default Logger;if(typeof module!=='undefined'&&module.exports){module.exports=Logger;}